class Solution {
public:
    int longestSubarray(vector<int>& nums, int k) {
        unordered_map<int, int> freq;
        int left = 0, repeated = 0, ans = 0;

        for (int right = 0; right < nums.size(); right++) {
            freq[nums[right]]++;

            if (freq[nums[right]] == 2)
                repeated++;

            while (repeated > k) {
                freq[nums[left]]--;

                if (freq[nums[left]] == 1)
                    repeated--;

                left++;
            }

            ans = max(ans, right - left + 1);
        }

        return ans;
    }
};

