class Solution {
public:
    bool isPalindrome(long long n) {
        long long rev = 0, temp = n;

        while (temp > 0) {
            rev = rev * 10 + temp % 10;
            temp /= 10;
        }

        return rev == n;
    }

    long long nextPalindrome(long long n) {
        n++;

        while (!isPalindrome(n))
            n++;

        return n;
    }
};

