class Solution {
public:
    int minCost(vector<vector<int>>& grid) {
        int n = grid.size(), m = grid[0].size();
        vector<vector<int>> dist(n, vector<int>(m, INT_MAX));
        queue<pair<int,int>> q;

        dist[0][0] = 0;
        q.push({0,0});

        int dx[4] = {0,0,1,-1};
        int dy[4] = {1,-1,0,0};

        while(!q.empty()) {
            auto [x,y] = q.front();
            q.pop();

            for(int d=0; d<4; d++) {
                int nx = x + dx[d];
                int ny = y + dy[d];

                if(nx>=0 && ny>=0 && nx<n && ny<m) {
                    int cost = dist[x][y] + (grid[x][y] != d+1);

                    if(cost < dist[nx][ny]) {
                        dist[nx][ny] = cost;
                        q.push({nx,ny});
                    }
                }
            }
        }

        return dist[n-1][m-1];
    }
};

