class Solution {
public:
    int minMoves(vector<vector<int>>& grid) {
        int n = grid.size();
        queue<vector<int>> q;
        set<vector<int>> vis;

        q.push({0,0,0});
        vis.insert({0,0,0});

        while(!q.empty()) {
            auto cur = q.front();
            q.pop();

            int x = cur[0], y = cur[1], d = cur[2];

            if(x == n-1 && y == n-1)
                return d;

            int dx[4]={1,-1,0,0};
            int dy[4]={0,0,1,-1};

            for(int i=0;i<4;i++) {
                int nx=x+dx[i], ny=y+dy[i];

                if(nx>=0 && ny>=0 && nx<n && ny<n && grid[nx][ny]==0) {
                    vector<int> nxt={nx,ny,d+1};

                    if(!vis.count(nxt)) {
                        vis.insert(nxt);
                        q.push(nxt);
                    }
                }
            }
        }

        return -1;
    }
};

