public:
    int maximizeSum(vector<vector<int>>& points) {
        sort(points.begin(), points.end(), [](auto &a, auto &b){
            return a[1] > b[1];
        });

        unordered_set<int> used;
        int ans=0;

        for(auto &p:points){
            if(!used.count(p[0])){
                ans+=p[1];
                used.insert(p[0]);
            }

            if(used.size()==3) break;
        }

        return ans;
    }
};

