class Solution {
public:
    int minimumXOR(vector<int>& nums) {
        int n = nums.size();
        int total = 1 << n;
        int ans = INT_MAX;

        for (int mask = 1; mask < total - 1; mask++) {
            int xor1 = 0, xor2 = 0;

            for (int i = 0; i < n; i++) {
                if (mask & (1 << i))
                    xor1 ^= nums[i];
                else
                    xor2 ^= nums[i];
            }

            ans = min(ans, abs(xor1 - xor2));
        }

        return ans;
    }
};

