        unordered_map<char, int> freq;

        for (char c : s)
            freq[c]++;

        if (freq.size() <= k)
            return 0;

        vector<int> counts;

        for (auto& it : freq)
            counts.push_back(it.second);

        sort(counts.begin(), counts.end());

        int remove = freq.size() - k;
        int ans = 0;

        for (int i = 0; i < remove; i++)
            ans += counts[i];

        return ans;
    }
