    vector<vector<int>> minAbsDiff(vector<vector<int>>& grid, int k) {
        int n = grid.size();
        int m = grid[0].size();

        vector<vector<int>> ans(n - k + 1, vector<int>(m - k + 1));

        for (int i = 0; i <= n - k; i++) {
            for (int j = 0; j <= m - k; j++) {
                vector<int> arr;

                for (int x = i; x < i + k; x++) {
                    for (int y = j; y < j + k; y++) {
                        arr.push_back(grid[x][y]);
                    }
                }

                sort(arr.begin(), arr.end());

                int best = INT_MAX;

                for (int p = 1; p < arr.size(); p++) {
                    best = min(best, arr[p] - arr[p - 1]);
                }

                ans[i][j] = best;
            }
        }

        return ans;
    }
};

