class Solution {
public:
    bool isPrime(int n) {
        if (n < 2)
            return false;

        for (int i = 2; i * i <= n; i++) {
            if (n % i == 0)
                return false;
        }

        return true;
    }

    int maximizePrimes(vector<int>& nums) {
        unordered_set<int> left, right;

        for (int num : nums) {
            if (isPrime(num))
                right.insert(num);
        }

        int ans = right.size();

        for (int num : nums) {
            if (isPrime(num)) {
                left.insert(num);
                right.erase(num);
            }

            ans = max(ans, (int)(left.size() + right.size()));
        }

        return ans;
    }
};

