class Solution {
public:
    int shortestSubarray(vector<int>& nums) {
        int n = nums.size();
        int left = n;
        int right = 0;

        for (int i = 1; i < n; i++) {
            if (nums[i] < nums[i - 1])
                right = i;
        }

        for (int i = n - 2; i >= 0; i--) {
            if (nums[i] > nums[i + 1])
                left = i;
        }

        return right > left ? right - left + 1 : 0;
    }
};

