class Solution {
public:
    int minimumMoves(vector<string>& classroom) {
        int n = classroom.size();
        int m = classroom[0].size();

        queue<vector<int>> q;
        vector<vector<int>> visited(n, vector<int>(m, 0));

        q.push({0, 0, 0});
        visited[0][0] = 1;

        int dirs[4][2] = {{1,0},{-1,0},{0,1},{0,-1}};

        while (!q.empty()) {
            auto cur = q.front();
            q.pop();

            int x = cur[0];
            int y = cur[1];
            int dist = cur[2];

            if (x == n - 1 && y == m - 1)
                return dist;

            for (auto& d : dirs) {
                int nx = x + d[0];
                int ny = y + d[1];

                if (nx >= 0 && ny >= 0 && nx < n && ny < m &&
                    !visited[nx][ny] && classroom[nx][ny] != '#') {
                    visited[nx][ny] = 1;
                    q.push({nx, ny, dist + 1});
                }
            }
        }

        return -1;
    }
};

