class Solution {
public:
    int maximumPath(int n, vector<vector<int>>& edges, int k) {
        vector<int> dp(n, INT_MIN);
        dp[0] = 0;

        for (int step = 0; step < k; step++) {
            vector<int> next = dp;

            for (auto& e : edges) {
                int u = e[0], v = e[1], w = e[2];

                if (dp[u] != INT_MIN)
                    next[v] = max(next[v], dp[u] + w);
            }

            dp = next;
        }

        return *max_element(dp.begin(), dp.end());
    }
};

